Code.Terraform:
```hcl
resource "aws_glue_job" "example" {
  name     = "<job_name>"
  role_arn = "<role_arn>"

  command {
    script_location = "s3://<bucket>/script.py"
  }

  default_arguments = {
    "--secret_name" = aws_secretsmanager_secret_version.example.secret_string  # Reference secret from Secrets Manager instead of plaintext
  }
}
```
